scwin.f_RetrieveSecondCoCls = async function (param1) {
  if (param1 == "") {
    ds_clntNo.removeAll();
    ds_clntNo.insertRow(0);
    ds_clntNo.setCellData(0, "code", "");
    ds_clntNo.setCellData(0, "name", "전체");
  } else {
    dma_clntNo.set("sysCd", "EquipmentNonUsableEBC");
    dma_clntNo.set("queryId", "retrivecCoClsComboCodeList");
    dma_clntNo.set("param1", param1);
    ds_clntNo.removeAll();

    //submit 처리.
    let objSubmit = await $c.sbm.execute($p, sbm_clntNo);
    if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
      await scwin.sbm_clntNo_submitdone();
    }
  }
};
scwin.sbm_clntNo_submitdone = async function (e) {
  //for=ds_clntNo event=OnLoadCompleted
  ds_clntNo.insertRow(0);
  ds_clntNo.setCellData(0, "code", "");
  ds_clntNo.setCellData(0, "name", "전체");
  lc_clntNo.setSelectedIndex(0);
};

